export const Multiple = () => {
  const [selectedKeys, setSelectedKeys] = React.useState<string[]>([]);
  const update = (type: string, v: string[]) => {
    console.log(type, v);
    setSelectedKeys(v);
  };
  const MultipleMenu = (
    <Menu
      mode="vertical"
      multiple
      selectable
      selectedKeys={selectedKeys}
      onSelect={info => update('onSelect', info.selectedKeys as any)}
      onDeselect={info => update('onDeselect', info.selectedKeys as any)}
    >
      <Menu.Item>1</Menu.Item>
      <Menu.Item>2</Menu.Item>
      <Menu.Item>3</Menu.Item>
    </Menu>
  );
  return (
    <Dropdown trigger="click" overlay={MultipleMenu} placement="bottomCenter">
      <Button style={{ marginLeft: 'auto' }}>bottomRight</Button>
    </Dropdown>
  );
};

